```css
/* Project container ka CSS */
.project-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    padding: 2em;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
    backdrop-filter: blur(5.9px);
    -webkit-backdrop-filter: blur(5.9px);
}

/* Project ka CSS */
.project {
    background: #fff;
    padding: 1em;
    border-radius: 16px;
    box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
    margin: 1em;
    width: calc(33.33% - 2em);
    transition: transform 0.2s ease;
}

.project:hover {
    transform: scale(1.1);
}

/* Project image ka CSS */
.project img {
    width: 100%;
    height: 150px;
    object-fit: cover;
    border-radius: 16px 16px 0 0;
}

/* Project title ka CSS */
.project h2 {
    font-size: 1.5em;
    font-weight: bold;
    margin-bottom: 0.5em;
}

/* Project description ka CSS */
.project p {
    font-size: 1em;
    color: #666;
    margin-bottom: 1em;
}

/* Project button ka CSS */
.project button {
    background: #ff69b4;
    color: #fff;
    padding: 0.5em 1em;
    border: none;
    border-radius: 16px;
    cursor: pointer;
    transition: background 0.2s ease;
}

.project button:hover {
    background: #ffe6cc;
}

/* Project active ka CSS */
.project.active {
    background: #ff69b4;
    color: #fff;
    transform: scale(1.1);
}

.project.active h2 {
    color: #fff;
}

.project.active p {
    color: #fff;
}

/* Responsive design ka CSS */
@media only screen and (max-width: 768px) {
    .project-container {
        flex-direction: column;
    }
    .project {
        width: 100%;
        margin: 1em 0;
    }
}

@media only screen and (max-width: 480px) {
    .project-container {
        padding: 1em;
    }
    .project {
        padding: 0.5em;
    }
}
```

